var e=[{id:`L2_1`,type:`dialog`,speaker:`KNIGHT_PRYDWEN_ESPR_NULL`,text:{KOREA:`심연을 오랫동안 들여다본다면, 심연 또한 이쪽을 들여다본다고 하지.`,JPN:`深淵を長いこと覗き込んでいると、深淵もまたこちらを覗き込んでくるという。`,ENG:`They say that if you gaze long into the abyss, the abyss gazes back.`,TWN:`如果你長時間凝視深淵，深淵也會回望你。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KNIGHT_PRYDWEN_ESPR_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`KNIGHT_PRYDWEN_ESPR_NULL`,text:{KOREA:`그러니 이름을 버린 기사는 심연의 밑바닥에서 네놈을 들여다보겠다.`,JPN:`ならば名を捨てた騎士は、深淵の底から貴様を覗き込むとしよう。`,ENG:`Then I, the nameless knight, shall watch you from the depths of that abyss.`,TWN:`所以放棄名字的騎士，將在深淵底部監視你。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KNIGHT_PRYDWEN_ESPR_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`KNIGHT_PRYDWEN_ESPR_NULL`,text:{KOREA:`과거, 내가 넘지 못했던 무한한 좌절과 절망의 끝에서 네놈이 무엇을 이룰 수 있는지 지켜보기 위해서.`,JPN:`かつて俺が越えられなかった無限の挫折と絶望の果てに、貴様が何を成し遂げるか……見届けるために。`,ENG:`To see what you will achieve at the very end of the endless despair I once could not overcome.`,TWN:`看看你能否在我不曾跨越的無限挫折與絕望的終點實現什麼。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KNIGHT_PRYDWEN_ESPR_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};